import{_ as t}from"./chunks/panel-dashboard.Ddd5T6mA.js";import{_ as e,o as i,c as r,a2 as s}from"./chunks/framework.CuEaBji2.js";const _=JSON.parse('{"title":"流量额度","description":"","frontmatter":{},"headers":[],"relativePath":"guides/traffic-quota.md","filePath":"guides/traffic-quota.md","lastUpdated":1782021666000}'),d={name:"guides/traffic-quota.md"};function l(n,a,o,p,h,c){return i(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="流量额度" tabindex="-1">流量额度 <a class="header-anchor" href="#流量额度" aria-label="Permalink to &quot;流量额度&quot;">​</a></h1><p>控制面按 Agent 节点统计流量，支持设置月度额度和超额阻断。</p><h2 id="查看流量" tabindex="-1">查看流量 <a class="header-anchor" href="#查看流量" aria-label="Permalink to &quot;查看流量&quot;">​</a></h2><p>面板首页的仪表盘展示流量概览：已用 / 总额度、已阻断节点数、流量趋势图。</p><p><img src="'+t+'" alt="仪表盘首页"></p><h2 id="配置流量策略" tabindex="-1">配置流量策略 <a class="header-anchor" href="#配置流量策略" aria-label="Permalink to &quot;配置流量策略&quot;">​</a></h2><p>在节点详情页设置：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>计数方向</td><td>哪些流量计入额度：入站（rx）、出站（tx）、双向、取大值、混合公式</td></tr><tr><td>计费起始日</td><td>月度周期重置日期（1–31），默认 1 号</td></tr><tr><td>月度额度</td><td>每月最大流量。留空表示不限制</td></tr><tr><td>超额阻断</td><td>开启后达到额度会阻断该节点</td></tr></tbody></table><p>节点被阻断后，面板首页和节点列表会显示阻断状态。下个计费周期自动恢复。你也可以手动调高额度或关闭超额阻断让节点立即恢复。</p><h2 id="手动校准" tabindex="-1">手动校准 <a class="header-anchor" href="#手动校准" aria-label="Permalink to &quot;手动校准&quot;">​</a></h2><p>以下情况需要手动校准流量统计：</p><ul><li>更换网卡</li><li>重装操作系统</li><li>迁移数据到新服务器</li></ul><p>在节点详情页操作：设置基准偏移（增减固定量），或清除当前周期（归零）。校准后所有统计使用校准值。</p><h2 id="关闭流量统计" tabindex="-1">关闭流量统计 <a class="header-anchor" href="#关闭流量统计" aria-label="Permalink to &quot;关闭流量统计&quot;">​</a></h2><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_TRAFFIC_STATS_ENABLED</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>深入了解流量统计的实现原理，见 <a href="./../reference/traffic-accounting">流量统计原理</a>。</p>',16)])])}const b=e(d,[["render",l]]);export{_ as __pageData,b as default};
